  function syncTime(){if(!tracks.length)return;const track=tracks[index],duration=Number.isFinite(audio.duration)?audio.duration:track.duration_seconds,elapsed=audio.currentTime||0;$('elapsed').textContent=format(elapsed);$('remaining').textContent='−'+format(Math.max(0,duration-elapsed));draw();if(window.UIWidgets)window.UIWidgets.tick(trackData(track,elapsed),null,elapsed);}
  async function commitTrack(next,{resetAudio=true,mode=fixtureState}={}){index=(next+tracks.length)%tracks.length;$('fixtureTrack').value=String(index);currentWave=await waveform(tracks[index]);if(resetAudio){audio.src=localPath('tracks',tracks[index].audio_file);audio.load();}renderMetadata(tracks[index],mode);syncTime();if(window.UIWidgets)window.UIWidgets.syncTelemetry(trackData(tracks[index],audio.currentTime||0),audio.currentTime||0);}
  function clearTransition(){card.classList.remove('transition-forecast','transition-flicker','transition-persistence','transition-writing','transition-wave','transition-simple');$('incomingSignal').hidden=true;cover.classList.remove('cover-out','cover-in');transitioning=false;}
  async function typeTitle(value){const node=$('track');node.textContent='';for(let i=0;i<value.length;i++){node.textContent+=value[i];if(i===3)$('metadataBand').style.opacity='1';await sleep(22);}}
  async function simpleTransition(next,wasPlaying){card.classList.add('transition-simple');await sleep(160);await commitTrack(next,{mode:'transmitting'});if(wasPlaying){try{await audio.play();}catch(_){}}await sleep(120);clearTransition();setState('transmitting');}
  async function transitionTo(next){if(transitioning||next===index)return;transitioning=true;const wasPlaying=!audio.paused,nextTrack=tracks[next],nextWave=await waveform(nextTrack);if(reduced()){await simpleTransition(next,wasPlaying);return;}setState('incoming');$('incomingSignal').hidden=false;card.classList.add('transition-forecast');await sleep(700);card.classList.replace('transition-forecast','transition-flicker');await sleep(300);card.classList.replace('transition-flicker','transition-persistence');cover.classList.add('cover-out');await sleep(340);audio.pause();index=next;$('fixtureTrack').value=String(index);currentWave=nextWave;audio.src=localPath('tracks',tracks[index].audio_file);audio.load();setCover(nextTrack);cover.classList.remove('cover-out');cover.classList.add('cover-in');$('metadataBand').style.opacity='0';$('releaseId').textContent=nextTrack.release_id;$('release').textContent=nextTrack.release_title;$('trackNumber').textContent=String(nextTrack.track_number).padStart(2,'0');card.classList.replace('transition-persistence','transition-writing');await typeTitle(nextTrack.title);$('metadataBand').style.opacity='1';card.classList.replace('transition-writing','transition-wave');syncTime();if(window.UIWidgets)window.UIWidgets.syncTelemetry(trackData(nextTrack,0),0);await sleep(850);if(wasPlaying){try{await audio.play();}catch(_){}}clearTransition();setState('transmitting');}
  async function engage(){if(fixtureState==='unavailable')return setState('unavailable');setState('acquiring');try{await audio.play();setState('transmitting');setupSpectrum();}catch(_){setState('standby');}}
