  function drawSpectrum(){const canvas=$('spectrum'),rect=canvas.getBoundingClientRect();if(rect.width&&rect.height){const ratio=Math.min(devicePixelRatio||1,2);canvas.width=Math.round(rect.width*ratio);canvas.height=Math.round(rect.height*ratio);const context2=canvas.getContext('2d');context2.setTransform(ratio,0,0,ratio,0,0);context2.clearRect(0,0,rect.width,rect.height);const values=analyser?new Uint8Array(analyser.frequencyBinCount):[],color=accent().join(' ');if(analyser)analyser.getByteFrequencyData(values);for(let i=0;i<32;i++){const value=values.length?values[i]:0,height=Math.max(2,value/255*rect.height*.9);context2.fillStyle='rgb('+color+')';context2.globalAlpha=.2+value/510;context2.fillRect(i*rect.width/32,rect.height-height,Math.max(1,rect.width/32-2),height);}context2.globalAlpha=1;}raf=requestAnimationFrame(drawSpectrum);}
  function tick(){syncTime();requestAnimationFrame(tick);}async function init(){const response=await fetch('../player-widget-lab/fixtures.json'),fixture=await response.json();tracks=fixture.tracks;tracks.forEach((track,n)=>{const option=document.createElement('option');option.value=n;option.textContent=track.title;$('fixtureTrack').append(option);});await commitTrack(0,{mode:'standby'});setState('standby');clock();setInterval(clock,30000);tick();}
  overlay.addEventListener('pointerdown',engage);window.addEventListener('keydown',event=>{if(!overlay.hidden&&(event.key==='Enter'||event.key===' ')){event.preventDefault();engage();}});$('fixtureTrack').addEventListener('change',event=>transitionTo(Number(event.target.value)));$('fixtureState').addEventListener('change',event=>{const state=event.target.value;if(state==='normal'){setState(audio.paused?'standby':'transmitting');renderMetadata(tracks[index],fixtureState);}else{if(state==='unavailable')audio.pause();setState(state);renderMetadata(tracks[index],state);}syncTime();});$('reducedMotion').addEventListener('change',event=>body.classList.toggle('reduced-motion',event.target.checked));audio.addEventListener('ended',()=>transitionTo((index+1)%tracks.length));audio.addEventListener('error',()=>setState('unavailable'));window.addEventListener('mdk:palette-changed',draw);window.addEventListener('beforeunload',()=>cancelAnimationFrame(raf));init().catch(()=>setState('unavailable'));
